-- ==========================================================
-- accounts seed — Түмэн Тээх ХХК БОДИТ дансны чарт (Gbalance 2025)
-- Нийт: 159 данс. fs_line нь E-balance тайлангийн мөртэй холбоотой.
-- Хүснэгт хоосон үед л оруулна. Supabase SQL Editor-д ажиллуулна.
-- ==========================================================

DO $$
BEGIN
IF (SELECT COUNT(*) FROM accounts) = 0 THEN


PERFORM setval(pg_get_serial_sequence('accounts','id'), (SELECT MAX(id) FROM accounts));

END IF;
END $$;
